import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProductDetail({ token }) {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [size, setSize] = useState('');
  const [color, setColor] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      const res = await axios.get(`/api/products/${id}`);
      setProduct(res.data);
      if (res.data.sizes && res.data.sizes.length > 0) {
        setSize(res.data.sizes[0]);
      }
      if (res.data.colors && res.data.colors.length > 0) {
        setColor(res.data.colors[0]);
      }
    } catch (err) {
      setError('Product not found');
    } finally {
      setLoading(false);
    }
  };

  const handleAddToCart = async (e) => {
    e.preventDefault();
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      await axios.post('/api/cart/add',
        { productId: id, quantity: parseInt(quantity), size, color },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setSuccess('Added to cart!');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to add to cart');
    }
  };

  if (loading) return <div className="loading">Loading...</div>;
  if (error) return <div className="error-message">{error}</div>;
  if (!product) return <div className="error-message">Product not found</div>;

  return (
    <div style={{ display: 'flex', gap: '30px', marginTop: '20px' }}>
      <div style={{ flex: 1 }}>
        <img src={product.image} alt={product.name} style={{ width: '100%', maxWidth: '500px' }} />
      </div>
      <div style={{ flex: 1 }}>
        <h1>{product.name}</h1>
        <p style={{ fontSize: '24px', color: '#ff6b6b', fontWeight: 'bold', margin: '20px 0' }}>
          ฿{product.price}
        </p>
        <p style={{ color: '#666', lineHeight: '1.6' }}>{product.description}</p>

        <form onSubmit={handleAddToCart} style={{ background: 'white', padding: '20px', borderRadius: '8px', marginTop: '20px' }}>
          {success && <div className="success-message">{success}</div>}
          {error && <div className="error-message">{error}</div>}

          {product.sizes && product.sizes.length > 0 && (
            <div className="form-group">
              <label>Size</label>
              <select value={size} onChange={(e) => setSize(e.target.value)}>
                {product.sizes.map(s => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          )}

          {product.colors && product.colors.length > 0 && (
            <div className="form-group">
              <label>Color</label>
              <select value={color} onChange={(e) => setColor(e.target.value)}>
                {product.colors.map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          )}

          <div className="form-group">
            <label>Quantity</label>
            <input
              type="number"
              min="1"
              max="10"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
            />
          </div>

          <button type="submit" style={{ width: '100%' }}>Add to Cart</button>
        </form>
      </div>
    </div>
  );
}

export default ProductDetail;
